function run(): void {
  console.log('Wave 7: 600 new movie clips');
  let created = 0, skipped = 0;
  for (const v of VIDEOS) {
    const existing = s.fv.get(v.youtubeId) as any;
    if (existing) {
      skipped++;
      continue;
    }
    try {
      s.iv.run(v.videoId, v.youtubeId, v.title, v.movieTitle, v.genre, v.difficulty);
      s.ic.run(v.videoId);
      created++;
    } catch (err: any) {
      console.log(`  Warning: ${v.videoId}: ${err.message}`);
    }
  }
  console.log(`Created: ${created}, Skipped (existing): ${skipped}`);
  const total = (db.prepare('SELECT COUNT(*) as n FROM videos').get() as any).n;
  console.log(`Total videos in DB: ${total}`);
  db.close();
}
run();
